    37→const (
    38→	// Injected bound service account token expiration which triggers monitoring of its time-bound feature.
    39→	WarnOnlyBoundTokenExpirationSeconds = 60*60 + 7
    40→
    41→	// Extended expiration for those modified tokens involved in safe rollout if time-bound feature.
    42→	ExpirationExtensionSeconds = 24 * 365 * 60 * 60
    43→)
