    56→type kubernetes struct {
    57→	Namespace string           `json:"namespace,omitempty"`
    58→	Svcacct   ref              `json:"serviceaccount,omitempty"`
    59→	Pod       *ref             `json:"pod,omitempty"`
    60→	Secret    *ref             `json:"secret,omitempty"`
    61→	Node      *ref             `json:"node,omitempty"`
    62→	WarnAfter *jwt.NumericDate `json:"warnafter,omitempty"`
