    70→func Claims(sa core.ServiceAccount, pod *core.Pod, secret *core.Secret, node *core.Node, expirationSeconds, warnafter int64, audience []string) (*jwt.Claims, interface{}, error) {
    71→	now := now()
    72→	sc := &jwt.Claims{
    73→		Subject:   apiserverserviceaccount.MakeUsername(sa.Namespace, sa.Name),
    74→		Audience:  jwt.Audience(audience),
    75→		IssuedAt:  jwt.NewNumericDate(now),
    76→		NotBefore: jwt.NewNumericDate(now),
    77→		Expiry:    jwt.NewNumericDate(now.Add(time.Duration(expirationSeconds) * time.Second)),
    78→	}
    79→	if utilfeature.DefaultFeatureGate.Enabled(features.ServiceAccountTokenJTI) {
    80→		sc.ID = newUUID()
    81→	}
    82→	pc := &privateClaims{
    83→		Kubernetes: kubernetes{
    84→			Namespace: sa.Namespace,
    85→			Svcacct: ref{
    86→				Name: sa.Name,
    87→				UID:  string(sa.UID),
    88→			},
    89→		},
    90→	}
    91→
    92→	if secret != nil && (node != nil || pod != nil) {
    93→		return nil, nil, fmt.Errorf("internal error, token can only be bound to one object type")
    94→	}
    95→	switch {
    96→	case pod != nil:
    97→		pc.Kubernetes.Pod = &ref{
    98→			Name: pod.Name,
    99→			UID:  string(pod.UID),
   100→		}
   101→		if utilfeature.DefaultFeatureGate.Enabled(features.ServiceAccountTokenPodNodeInfo) {
   102→			// if this is bound to a pod and the node information is available, persist that too
   103→			if node != nil {
   104→				pc.Kubernetes.Node = &ref{
   105→					Name: node.Name,
   106→					UID:  string(node.UID),
   107→				}
   108→			}
   109→		}
   110→	case secret != nil:
   111→		pc.Kubernetes.Secret = &ref{
   112→			Name: secret.Name,
   113→			UID:  string(secret.UID),
   114→		}
   115→	case node != nil:
   116→		if !utilfeature.DefaultFeatureGate.Enabled(features.ServiceAccountTokenNodeBinding) {
   117→			return nil, nil, fmt.Errorf("token bound to Node object requested, but %q feature gate is disabled", features.ServiceAccountTokenNodeBinding)
   118→		}
   119→		pc.Kubernetes.Node = &ref{
   120→			Name: node.Name,
   121→			UID:  string(node.UID),
   122→		}
   123→	}
   124→
   125→	if warnafter != 0 {
   126→		pc.Kubernetes.WarnAfter = jwt.NewNumericDate(now.Add(time.Duration(warnafter) * time.Second))
   127→	}
   128→
   129→	return sc, pc, nil
   130→}
